function extrairJSON(texto) {
  // Se já for objeto, retorna direto
  if (typeof texto === 'object' && texto !== null) return texto;

  // Remove markdown code blocks se houver
  let limpo = texto.replace(/```json|```/g, '').trim();

  // Tenta parse direto
  try {
    const parsed = JSON.parse(limpo);
    // Se o resultado ainda for string, faz parse de novo (JSON dentro de JSON)
    if (typeof parsed === 'string') return JSON.parse(parsed);
    return parsed;
  } catch {}

  // Tenta extrair entre o primeiro { e último }
  const inicio = limpo.indexOf('{');
  const fim = limpo.lastIndexOf('}');
  if (inicio !== -1 && fim !== -1) {
    try {
      const trecho = limpo.substring(inicio, fim + 1);
      const parsed = JSON.parse(trecho);
      if (typeof parsed === 'string') return JSON.parse(parsed);
      return parsed;
    } catch {}
  }

  throw new Error('Nenhum JSON válido encontrado no output da IA.\nConteúdo recebido: ' + String(texto).substring(0, 300));
}

// Pega o output — pode vir como string ou objeto
const item = $input.first().json;
const raw = typeof item.output === 'string' ? item.output : JSON.stringify(item.output);

const parsed = extrairJSON(raw);

// Data atual no horário de São Paulo
const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const [dataParte, horaParte] = agora.split(', ');
const [dia, mes, ano] = dataParte.split('/');
const [horas, minutos, segundos] = horaParte.split(':');
const milissegundos = String(Date.now()).slice(-3);
const data_criacao = `${dia.padStart(2,'0')}/${mes.padStart(2,'0')}/${ano} ${horas.padStart(2,'0')}:${minutos.padStart(2,'0')}`;
const id_post = `post_${ano}${mes}${dia}_${horas}${minutos}${segundos}_${milissegundos}_1`;

return [{ json: { ...parsed, data_criacao, id_post } }];
